 * Personality Judge — Cost Controls
 * ====================================
 * Hard limits. Never bypassed. Never configurable at runtime.
 */

export const JUDGE_LIMITS = {
  /** Hard ceiling on judge calls per day */
  daily_judge_calls_max: 100,
  /** Warn when daily judge cost exceeds this */
  daily_cost_warning_threshold: 2.00,
  /** Block ALL judge calls when daily cost exceeds this */
  daily_cost_hard_limit: 5.00,
  /** Max models in a single personality benchmark run */
  max_models_per_run: 5,
  /** Truncate model responses to this many tokens before sending to judge */
  response_truncation_tokens: 300,
  /** Max tokens for judge response (JSON only) */
  judge_max_tokens: 150,
} as const;

/** Judge model options — default is Budget (Sonnet) */
export const JUDGE_MODELS = {
  budget: {
    id: "claude-sonnet-4-6",
    provider: "squidley.integration.provider-anthropic",
    label: "Claude Sonnet 4.6",
    cost_per_m_input: 3.00,
    cost_per_m_output: 15.00,
  },
  standard: {
    id: "claude-opus-4-6",
    provider: "squidley.integration.provider-anthropic",
    label: "Claude Opus 4.6",
    cost_per_m_input: 15.00,
    cost_per_m_output: 75.00,
  },
} as const;

export type JudgeTier = keyof typeof JUDGE_MODELS;

/** Estimate cost for a personality benchmark run */
export function estimatePersonalityCost(
  modelCount: number,
  testCount: number,
  judgeTier: JudgeTier,
): { modelCost: number; judgeCost: number; totalCost: number; judgeCallCount: number } {
  const judgeModel = JUDGE_MODELS[judgeTier];
  const judgeCallCount = modelCount * testCount;
  // ~600 input tokens + ~80 output tokens per judge call
  const judgeCost = judgeCallCount * ((600 / 1_000_000) * judgeModel.cost_per_m_input + (80 / 1_000_000) * judgeModel.cost_per_m_output);
  // ~200 input + ~100 output tokens per model call (personality prompts are short)
  const modelCost = judgeCallCount * ((200 / 1_000_000) * 0.50 + (100 / 1_000_000) * 1.50); // estimate with cheap model
  return {
    modelCost: Math.round(modelCost * 10000) / 10000,
    judgeCost: Math.round(judgeCost * 10000) / 10000,
    totalCost: Math.round((modelCost + judgeCost) * 10000) / 10000,
    judgeCallCount,
  };
}

// ── Daily tracker (in-memory, resets on restart) ────────────────────────────

let dailyJudgeCalls = 0;
let dailyCost = 0;
let lastResetDate = new Date().toISOString().slice(0, 10);

function resetIfNewDay() {
  const today = new Date().toISOString().slice(0, 10);
  if (today !== lastResetDate) {
    dailyJudgeCalls = 0;
    dailyCost = 0;
    lastResetDate = today;
  }
}

export function canRunJudge(): { allowed: boolean; reason?: string } {
  resetIfNewDay();
  if (dailyJudgeCalls >= JUDGE_LIMITS.daily_judge_calls_max) {
    return { allowed: false, reason: `Daily judge call limit reached (${dailyJudgeCalls}/${JUDGE_LIMITS.daily_judge_calls_max})` };
  }
  if (dailyCost >= JUDGE_LIMITS.daily_cost_hard_limit) {
    return { allowed: false, reason: `Daily judge cost limit reached ($${dailyCost.toFixed(2)}/$${JUDGE_LIMITS.daily_cost_hard_limit.toFixed(2)})` };
  }
  return { allowed: true };
}

export function recordJudgeCall(cost: number) {
  resetIfNewDay();
  dailyJudgeCalls++;
  dailyCost += cost;
}

export function getJudgeUsage(): { calls: number; cost: number; limit: number; costLimit: number } {
  resetIfNewDay();
  return { calls: dailyJudgeCalls, cost: dailyCost, limit: JUDGE_LIMITS.daily_judge_calls_max, costLimit: JUDGE_LIMITS.daily_cost_hard_limit };
}
