            "originalContent": "/**
 * Personality Loader
 * ===================
 * Scans personalities/ directory, hot-reloads every 60s.
 * Validates schema on load — malformed files logged and skipped.
 * Exports getPersonality(), listPersonalities(), getActivePersonality(),
 * and setActivePersonality().
 *
 * Supports two JSON formats:
 *   Legacy: requires id, type, description, colloquium_prompt, symposium_prompt
 *   Flexible: requires name + prompt (id derived from filename, other fields get defaults)
 */

import { readdir, readFile } from "node:fs/promises";
import { basename, join } from "node:path";

export interface Personality {
  id: string;
  name: string;
  description: string;
  type: "assistant" | "persona";
  default_for: string[];
  colloquium_prompt: string;
  symposium_prompt: string;
  prompt: string | undefined;
  character: string | undefined;
  voice: string | undefined;
  style: Record<string, string> | undefined;
  available_in_simple_mode: boolean;
  requires_lab_mode: boolean;
  tags: string[];
}

const personalities = new Map<string, Personality>();

// Active personality per module — defaults applied on first load
const activePersonalities: Record<string, string> = {
  colloquium: "fiona",
  symposium: "tactician",
};

let reloadInterval: ReturnType<typeof setInterval> | null = null;

function personalitiesDir(): string {
  const base = process.env["SQUIDLEY_BASE_DIR"] ?? process.cwd();
  return join(base, "apps/api/src/config/personalities");
}

/** Validate and normalize a personality JSON into the canonical interface. */
function normalize(data: unknown, filename: string): Personality | null {
  if (!data || typeof data !== "object") return null;
  const d = data as Record<string, unknown>;

  // Must have a name at minimum
  if (typeof d.name !== "string" || d.name.length === 0) return null;

  // Legacy format: has all required fields
  const isLegacy =
    typeof d.id === "string" && d.id.length > 0 &&
    typeof d.description === "string" &&
    (d.type === "assistant" || d.type === "persona") &&
    typeof d.colloquium_prompt === "string" &&
    typeof d.symposium_prompt === "string";

  // Flexible format: has name + prompt
  const isFlexible = typeof d.prompt === "string" && d.prompt.length > 0;

  if (!isLegacy && !isFlexible) {
    return null;
  }

  const id = typeof d.id === "string" && d.id.length > 0
    ? d.id
    : basename(filename, ".json");

  return {
    id,
    name: d.name as string,
    description: typeof d.description === "string" ? d.description : (d.name as string),
    type: (d.type === "assistant" || d.type === "persona") ? d.type : "assistant",
    default_for: Array.isArray(d.default_for) ? d.default_for as string[] : [],
    colloquium_prompt: typeof d.colloquium_prompt === "string" ? d.colloquium_prompt : (typeof d.prompt === "string" ? d.prompt : ""),
    symposium_prompt: typeof d.symposium_prompt === "string" ? d.symposium_prompt : (typeof d.prompt === "string" ? d.prompt : ""),
    prompt: typeof d.prompt === "string" ? d.prompt : undefined,
    character: typeof d.character === "string" ? d.character : undefined,
    voice: typeof d.voice === "string" ? d.voice : undefined,
    style: d.style && typeof d.style === "object" ? d.style as Record<string, string> : undefined,
    available_in_simple_mode: typeof d.available_in_simple_mode === "boolean" ? d.available_in_simple_mode : false,
    requires_lab_mode: typeof d.requires_lab_mode === "boolean" ? d.requires_lab_mode : false,
    tags: Array.isArray(d.tags) ? d.tags as string[] : [],
  };
}

async function loadAll(): Promise<void> {
  const dir = personalitiesDir();
  try {
    const files = await readdir(dir);
    const nextPersonalities = new Map<string, Personality>();

    for (const f of files) {
      if (!f.endsWith(".json")) continue;
      try {
        const raw = await readFile(join(dir, f), "utf-8");
        const parsed = JSON.parse(raw) as unknown;
        const personality = normalize(parsed, f);
        if (!personality) {
          console.warn(`[personality] skipping malformed: ${f}`);
          continue;
        }
        nextPersonalities.set(personality.id, personality);
      } catch (err) {
        console.warn(`[personality] failed to load ${f}: ${String(err)}`);
      }
    }

    personalities.clear();
    for (const [id, personality] of nextPersonalities) {
      personalities.set(id, personality);
    }

    for (const [moduleId, personalityId] of Object.entries(activePersonalities)) {
      if (!personalities.has(personalityId)) {
        delete activePersonalities[moduleId];
      }
    }

    // Apply defaults for modules that don't have an active personality
    for (const p of personalities.values()) {
      for (const mod of p.default_for ?? []) {
        if (!activePersonalities[mod]) {
          activePersonalities[mod] = p.id;
        }
      }
    }
  } catch {
    // Directory doesn't exist yet — will be created when personalities are added
  }
}

/** Initialize the personality system — call once on startup */
export async function initPersonalities(): Promise<void> {
  await loadAll();
  if (reloadInterval) clearInterval(reloadInterval);
  // Hot-reload every 60 seconds
  reloadInterval = setInterval(() => void loadAll(), 60_000);
}

/** Stop hot-reload */
export function stopPersonalities(): void {
  if (reloadInterval) clearInterval(reloadInterval);
  reloadInterval = null;
}

/** Get a personality by ID. Returns null if not found. */
export function getPersonality(id: string): Personality | null {
  return personalities.get(id) ?? null;
}

/** List all loaded personalities. */
export function listPersonalities(): Personality[] {
  return Array.from(personalities.values());
}

/** Get active personality for a module. */
export function getActivePersonality(moduleId: string): Personality {
  const fallbackId = moduleId === "colloquium" ? "fiona" : "squidley";
  const id = activePersonalities[moduleId] ?? fallbackId;
  return personalities.get(id) ?? personalities.get(fallbackId) ?? personalities.get("squidley") ?? {
    id: fallbackId, name: "Squidley", description: "Default",
    type: "assistant", default_for: ["colloquium"],
    colloquium_prompt: "", symposium_prompt: "",
    prompt: undefined, character: undefined, voice: undefined, style: undefined,
    available_in_simple_mode: false, requires_lab_mode: false, tags: [],
  };
}

/** Set active personality for a module. Returns the personality or null if not found. */
export function setActivePersonality(moduleId: string, personalityId: string): Personality | null {
  const p = personalities.get(personalityId);
  if (!p) return null;
  activePersonalities[moduleId] = personalityId;
  return p;
}

/** Get the active personality map (for API responses). */
export function getActiveMap(): Record<string, string> {
  return { ...activePersonalities };
}
