const activePersonalities: Record<string, string> = {
  colloquium: "fiona",
  symposium: "tactician",
};

let reloadInterval: ReturnType<typeof setInterval> | null = null;

function personalitiesDir(): string {
  const base = process.env["SQUIDLEY_BASE_DIR"] ?? process.cwd();
  return join(base, "apps/api/src/config/personalities");
